changeSet.sql:
-- Drop the existing primary key (hypertables need partition column in PK)
ALTER TABLE audit_log DROP CONSTRAINT audit_log_pkey;

-- Add composite primary key including created_at (required for hypertable)
ALTER TABLE audit_log ADD PRIMARY KEY (id, created_at);

-- Convert to hypertable with 1-day chunks
SELECT create_hypertable('audit_log', 'created_at', migrate_data => true, chunk_time_interval => INTERVAL '1 day');

-- Enable compression for chunks older than 7 days
ALTER TABLE audit_log SET (
    timescaledb.compress,
    timescaledb.compress_segmentby = 'actor_id',
    timescaledb.compress_orderby = 'created_at DESC'
);

-- Add compression policy: compress chunks older than 7 days
SELECT add_compression_policy('audit_log', INTERVAL '7 days');

-- Add retention policy: drop chunks older than 90 days
SELECT add_retention_policy('audit_log', INTERVAL '90 days');
